const req = $input.first().json;
const body = req.body || {};
const ts = new Date().toISOString();
const action = body.action || 'list';
const id = body.id || null;
return [{ json: { action, id, body, ts } }];

const item = $input.first().json;
const rows = item.__rows || [];
const ts = item.__ts || new Date().toISOString();
return [{ json: {
  __status: 200,
  __body: JSON.stringify({
    success: true,
    workflow: 'GDA.api.approvals-queue',
    action: 'list',
    dryRun: false,
    data: rows,
    meta: { count: rows.length, timestamp: ts },
    error: null
  })
}}];

const router = $('Router').first().json;
const body = router.body || {};
const ts = router.ts;
const id = body.id || null;
const confirmed = body.confirmed === true;
const doubleConfirmed = body.doubleConfirmed === true;
if (!id || !confirmed || !doubleConfirmed) {
  return [{ json: { __status: 400, __body: JSON.stringify({ success: false, workflow: 'GDA.api.approvals-queue', action: 'approve', dryRun: false, data: null, meta: { timestamp: ts }, error: { code: 'MISSING_CONFIRMATION', message: 'id, confirmed, and doubleConfirmed are all required.' } }) } }];
}
return [{ json: { id, ts, body, __validated: true } }];

const rows = $input.all();
const approve = $('Approve Item').first().json;
const ts = approve.ts;
const SAFE = ['read-only','dry-run'];
const BLOCKED = ['test-row','approval-required','unknown'];
if (!rows.length || !rows[0].json.id) {
  return [{ json: { __status: 404, __body: JSON.stringify({ success: false, workflow: 'GDA.api.approvals-queue', action: 'approve', dryRun: false, data: null, meta: { timestamp: ts }, error: { code: 'NOT_FOUND', message: 'Approval item not found.' } }), __skipWrite: true } }];
}
const item = rows[0].json;
const lane = (item.lane || 'unknown').toLowerCase();
const status = (item.status || '').toLowerCase();
if (['approved','rejected','changes_requested'].includes(status)) {
  return [{ json: { __status: 409, __body: JSON.stringify({ success: false, workflow: 'GDA.api.approvals-queue', action: 'approve', dryRun: false, data: { id: item.id, lane, status }, meta: { timestamp: ts }, error: { code: 'ALREADY_RESOLVED', message: 'Item is already ' + status + '.' } }), __skipWrite: true } }];
}
if (BLOCKED.includes(lane)) {
  return [{ json: { __status: 422, __body: JSON.stringify({ success: false, workflow: 'GDA.api.approvals-queue', action: 'approve', dryRun: false, data: { id: item.id, lane, status }, meta: { timestamp: ts }, error: { code: 'LANE_NOT_ENABLED', message: 'Live approval for lane "' + lane + '" is not enabled in this release.' } }), __skipWrite: true } }];
}
if (SAFE.includes(lane)) {
  return [{ json: { __skipWrite: false, id: item.id, lane, ts } }];
}
return [{ json: { __status: 422, __body: JSON.stringify({ success: false, workflow: 'GDA.api.approvals-queue', action: 'approve', dryRun: false, data: { id: item.id, lane, status }, meta: { timestamp: ts }, error: { code: 'LANE_NOT_ENABLED', message: 'Lane "' + lane + '" is not enabled for live approval.' } }), __skipWrite: true } }];

