const rows = $input.all();
const gate = $('Lane Gate').first().json;
const ts = gate.ts;
if (!rows.length) {
  return [{ json: { __status: 500, __body: JSON.stringify({ success: false, workflow: 'GDA.api.approvals-queue', action: 'approve', dryRun: false, data: null, meta: { timestamp: ts }, error: { code: 'WRITE_FAILED', message: 'DB write returned no rows.' } }) } }];
}
const row = rows[0].json;
return [{ json: { __status: 200, __body: JSON.stringify({ success: true, workflow: 'GDA.api.approvals-queue', action: 'approve', dryRun: false, data: { id: row.id, lane: row.lane, status: row.status, approved_at: row.approved_at, approved_by: row.approved_by }, meta: { timestamp: ts, note: 'Approval recorded. No workflow execution in this release.' }, error: null }) } }];

// Always fires. Reads 0-or-N rows from the named List Queue node.
// Works because continueOnFail:true on List Queue emits one error item when 0 rows,
// and $('List Queue').all() sees actual row data when rows exist.
const pgItems = $('List Queue').all();
const rows = pgItems.map(i => i.json).filter(r => r && typeof r.id !== 'undefined' && !r.error);
return [{ json: { __rows: rows, __ts: new Date().toISOString() } }];
